const wispUrl=localStorage.getItem("wispUrl")||("https:"===location.protocol?"wss":"ws")+"://"+location.host+"/wisp/";function createTransportScripts(){return new Promise((t=>{const e=document.createElement("script");e.src="epoxy/index.js",document.body.appendChild(e);const r=document.createElement("script");r.src="libcurl/index.cjs",document.body.appendChild(r);const o=setInterval((()=>{"undefined"!=typeof EpxMod&&"undefined"!=typeof CurlMod&&(clearInterval(o),t())}),100)}))}function setTransports(t){switch(t){case"libcurl":setLibcurlTransport();break;case"epoxy":default:setEpoxyTransport();break;case"bare":setBareTransport(localStorage.getItem("bare"))}}function setLibcurlTransport(){BareMux.SetTransport("CurlMod.LibcurlClient",{wisp:localStorage.getItem("wispUrl")||wispUrl})}function setDefaultTransport(){localStorage.getItem("transports")?setTransports():(localStorage.setItem("transports","epoxy"),setEpoxyTransport())}function refreshEpoxyTransport(){setTransports()}function setEpoxyTransport(){BareMux.SetTransport("EpxMod.EpoxyClient",{wisp:localStorage.getItem("wispUrl")||wispUrl})}function setBareTransport(t){BareMux.SetTransport("BareMod.BareClient",t)}